#define N 3

void compute_waiting_times_fcfs(int burst[], int n, int wait[]) {
    wait[0] = 0;
    for (int i = 1; i < n; i++)
        wait[i] = wait[i-1] + burst[i-1];
}

void compute_turnaround_times(int burst[], int wait[], int n, int turnaround[]) {
    for (int i = 0; i < n; i++)
        turnaround[i] = wait[i] + burst[i];
}

float compute_average(int array[], int n) {
    float total = 0;
    for (int i = 0; i < n; i++)
        total += array[i];
    return total / n;
}

validation.test_code:
void test_compute_waiting_times_fcfs_single(void) {
    int burst[] = {5};
    int wait[1];
    compute_waiting_times_fcfs(burst, 1, wait);
    TEST_ASSERT_EQUAL_INT(0, wait[0]);
}

void test_compute_waiting_times_fcfs_two(void) {
    int burst[] = {3, 2};
    int wait[2];
    compute_waiting_times_fcfs(burst, 2, wait);
    TEST_ASSERT_EQUAL_INT(0, wait[0]);
    TEST_ASSERT_EQUAL_INT(3, wait[1]);
}

void test_compute_waiting_times_fcfs_three(void) {
    int burst[] = {6, 3, 9};
    int wait[3];
    compute_waiting_times_fcfs(burst, 3, wait);
    TEST_ASSERT_EQUAL_INT(0, wait[0]);
    TEST_ASSERT_EQUAL_INT(6, wait[1]);
    TEST_ASSERT_EQUAL_INT(9, wait[2]);
}

void test_compute_turnaround_times(void) {
    int burst[] = {6, 3, 9};
    int wait[] = {0, 6, 9};
    int turnaround[3];
    compute_turnaround_times(burst, wait, 3, turnaround);
    TEST_ASSERT_EQUAL_INT(6, turnaround[0]);
    TEST_ASSERT_EQUAL_INT(9, turnaround[1]);
    TEST_ASSERT_EQUAL_INT(18, turnaround[2]);
}

void test_compute_average_wait(void) {
    int wait[] = {0, 6, 9};
    int avg_int = (int)(compute_average(wait, 3) * 100);
    TEST_ASSERT_EQUAL_INT(500, avg_int);
}

void test_compute_average_turnaround(void) {
    int turnaround[] = {6, 9, 18};
    int avg_int = (int)(compute_average(turnaround, 3) * 100);
    TEST_ASSERT_EQUAL_INT(1100, avg_int);
}

int main(void) {
    RUN_TEST(test_compute_waiting_times_fcfs_single);
    RUN_TEST(test_compute_waiting_times_fcfs_two);
    RUN_TEST(test_compute_waiting_times_fcfs_three);
    RUN_TEST(test_compute_turnaround_times);
    RUN_TEST(test_compute_average_wait);
    RUN_TEST(test_compute_average_turnaround);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

